<template>
  <div class="login">
    <van-nav-bar title="会员登录" left-arrow @click-left="$router.go(-1)" />
    <div class="container">
      <div class="title">
        <h3>手机号登录</h3>
        <p>未注册的手机号登录后将自动注册</p>
      </div>

      <div class="form">
        <div class="form-item">
          <input
            v-model="mobile"
            class="inp"
            maxlength="11"
            placeholder="请输入手机号码"
            type="text"
          />
        </div>
        <div class="form-item">
          <input
            v-model="picCode"
            class="inp"
            maxlength="5"
            placeholder="请输入图形验证码"
            type="text"
          />
          <img v-if="picUrl" :src="picUrl" alt="" @click="getPic" />
        </div>
        <div class="form-item">
          <input v-model="noteCode" class="inp" placeholder="请输入短信验证码" type="text" />
          <button @click="getCode">
            {{ second === totalSecond ? '获取验证码' : second + '秒后重新发送' }}
          </button>
        </div>
      </div>

      <div @click="login" class="login-btn">登录</div>
    </div>
  </div>
</template>

<script>
// import request from '@/utils/request'
import { getPicCode, getMsgCode, codeLogin } from '@/api/login'

export default {
  name: 'LoginPage',
  data() {
    return {
      picCode: '', // 用户输入的图形验证码
      mobile: '', // 手机号
      picKey: '',
      picUrl: '', // 返回base格式图片
      totalSecond: 60, // 总秒数
      second: 60, // 当前秒数，开定时器对 second--
      timerId: null,
      noteCode: ''
    }
  },
  async created() {
    this.getPic()
  },
  methods: {
    async getPic() {
      try {
        const {
          data: { base64, key }
        } = await getPicCode()
        this.picUrl = base64
        this.picKey = key
        console.log(this.picUrl)
        // this.$toast.success('刷新成功')
      } catch (err) {
        console.log(err)
      }
    },
    // 获取验证码
    async getCode() {
      if (!this.validFn()) {
        return
      }
      // 判断定时器是否还在，再判断当前秒数是否等于60
      if (this.timerId && this.second === this.totalSecond) {
        return
      }
      const res = await getMsgCode(this.picCode, this.picKey, this.mobile)
      console.log(res)
      this.$toast('验证码已发送')
      this.timerId = setInterval(() => {
        this.second--
        console.log('正在倒计时')

        if (this.second <= 0) {
          clearInterval(this.timerId)
          this.timerId = null
          this.second = this.totalSecond
        }
      }, 1000)
    },
    // 校验输入框内容
    validFn() {
      if (!/^1[3-9]\d{9}$/.test(this.mobile)) {
        this.$toast('请输入正确的手机号')
        return false
      }
      // 因为获取的是图形验证码，所以无法和用户输入的进行判断，永远为false
      if (!/^\w{4}$/.test(this.picCode)) {
        this.$toast('请输入正确的图形验证码')
        return false
      }
      return true
    },
    async login() {
      if (!this.validFn()) {
        return
      }
      if (!/^\w{6}$/.test(this.noteCode)) {
        this.$toast('请输入正确的短信验证码')
        return
      }
      const res = await codeLogin(this.mobile, this.noteCode)
      this.$store.commit('user/setUserInfo', res.data)
      console.log('vuex', this.$store.state)
      console.log(res)
      if (res.status === 200) {
        this.$toast('登录成功')

        const url = this.$route.query.backUrl || '/'
        console.log(url)
        this.$router.replace(url)
      }
    }
  },
  destroyed() {
    clearInterval(this.timerId)
  }
}
</script>

<style lang="less" scoped>
.container {
  padding: 49px 29px;

  .title {
    margin-bottom: 20px;

    h3 {
      font-size: 26px;
      font-weight: normal;
    }

    p {
      line-height: 40px;
      font-size: 14px;
      color: #b8b8b8;
    }
  }

  .form-item {
    border-bottom: 1px solid #f3f1f2;
    padding: 8px;
    margin-bottom: 14px;
    display: flex;
    align-items: center;

    .inp {
      display: block;
      border: none;
      outline: none;
      height: 32px;
      font-size: 14px;
      flex: 1;
    }

    img {
      width: 94px;
      height: 31px;
    }

    button {
      height: 31px;
      border: none;
      font-size: 13px;
      color: #cea26a;
      background-color: transparent;
      padding-right: 9px;
    }
  }

  .login-btn {
    width: 100%;
    height: 42px;
    margin-top: 39px;
    background: linear-gradient(90deg, #ecb53c, #ff9211);
    color: #fff;
    border-radius: 39px;
    box-shadow: 0 10px 20px 0 rgba(0, 0, 0, 0.1);
    letter-spacing: 2px;
    display: flex;
    justify-content: center;
    align-items: center;
  }
}
</style>
